package com.hospital.management.model;import java.math.BigDecimal;import java.time.*;import java.util.*;/** Aggregate bill header with charge lines and non-sensitive payment history. */public class Bill{private Long billId,patientId,appointmentId,doctorId;private String billNumber,patientNumber,patientName,doctorName,departmentName,status;private LocalDate billDate,appointmentDate;private BigDecimal subtotal,taxAmount,discountAmount,totalAmount,paidAmount,balanceAmount;private List<BillItem>items=new ArrayList<>();private List<Payment>payments=new ArrayList<>();private LocalDateTime createdAt,updatedAt;public Long getBillId(){return billId;}public void setBillId(Long v){billId=v;}public String getBillNumber(){return billNumber;}public void setBillNumber(String v){billNumber=v;}public Long getPatientId(){return patientId;}public void setPatientId(Long v){patientId=v;}public String getPatientNumber(){return patientNumber;}public void setPatientNumber(String v){patientNumber=v;}public String getPatientName(){return patientName;}public void setPatientName(String v){patientName=v;}public Long getAppointmentId(){return appointmentId;}public void setAppointmentId(Long v){appointmentId=v;}public LocalDate getAppointmentDate(){return appointmentDate;}public void setAppointmentDate(LocalDate v){appointmentDate=v;}public Long getDoctorId(){return doctorId;}public void setDoctorId(Long v){doctorId=v;}public String getDoctorName(){return doctorName;}public void setDoctorName(String v){doctorName=v;}public String getDepartmentName(){return departmentName;}public void setDepartmentName(String v){departmentName=v;}public LocalDate getBillDate(){return billDate;}public void setBillDate(LocalDate v){billDate=v;}public BigDecimal getSubtotal(){return subtotal;}public void setSubtotal(BigDecimal v){subtotal=v;}public BigDecimal getTaxAmount(){return taxAmount;}public void setTaxAmount(BigDecimal v){taxAmount=v;}public BigDecimal getDiscountAmount(){return discountAmount;}public void setDiscountAmount(BigDecimal v){discountAmount=v;}public BigDecimal getTotalAmount(){return totalAmount;}public void setTotalAmount(BigDecimal v){totalAmount=v;}public BigDecimal getPaidAmount(){return paidAmount;}public void setPaidAmount(BigDecimal v){paidAmount=v;}public BigDecimal getBalanceAmount(){return balanceAmount;}public void setBalanceAmount(BigDecimal v){balanceAmount=v;}public String getStatus(){return status;}public void setStatus(String v){status=v;}public List<BillItem>getItems(){return items;}public void setItems(List<BillItem>v){items=v==null?new ArrayList<>():new ArrayList<>(v);}public List<Payment>getPayments(){return payments;}public void setPayments(List<Payment>v){payments=v==null?new ArrayList<>():new ArrayList<>(v);}public LocalDateTime getCreatedAt(){return createdAt;}public void setCreatedAt(LocalDateTime v){createdAt=v;}public LocalDateTime getUpdatedAt(){return updatedAt;}public void setUpdatedAt(LocalDateTime v){updatedAt=v;}public boolean equals(Object o){return this==o||(o instanceof Bill b&&billId!=null&&billId.equals(b.billId));}public int hashCode(){return Objects.hashCode(billId);}public String toString(){return"Bill{id="+billId+", number="+billNumber+", status="+status+"}";}}
